#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define GAMMA 1.4f
#define NDIM 3
#define NNB 4
#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)
#define RK 3

typedef struct {
    float x;
    float y;
    float z;
} float3;

inline void compute_velocity(float density, float3 momentum, __private float3* velocity) {
    velocity->x = momentum.x / density;
    velocity->y = momentum.y / density;
    velocity->z = momentum.z / density;
}

inline float compute_speed_sqd(float3 velocity) {
    return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

inline float compute_pressure(float density, float density_energy, float speed_sqd) {
    return (GAMMA - 1.0f) * (density_energy - 0.5f * density * speed_sqd);
}

inline float compute_speed_of_sound(float density, float pressure) {
    return sqrt(GAMMA * pressure / density);
}

inline void compute_flux_contribution(float density, float3 momentum, float density_energy, float pressure, float3 velocity,
                                      __private float3* fc_momentum_x, __private float3* fc_momentum_y, __private float3* fc_momentum_z, __private float3* fc_density_energy) {
    fc_momentum_x->x = velocity.x * momentum.x + pressure;
    fc_momentum_x->y = velocity.x * momentum.y;
    fc_momentum_x->z = velocity.x * momentum.z;

    fc_momentum_y->x = fc_momentum_x->y;
    fc_momentum_y->y = velocity.y * momentum.y + pressure;
    fc_momentum_y->z = velocity.y * momentum.z;

    fc_momentum_z->x = fc_momentum_x->z;
    fc_momentum_z->y = fc_momentum_y->z;
    fc_momentum_z->z = velocity.z * momentum.z + pressure;

    float de_p = density_energy + pressure;
    fc_density_energy->x = velocity.x * de_p;
    fc_density_energy->y = velocity.y * de_p;
    fc_density_energy->z = velocity.z * de_p;
}

__kernel void initialize_variables(__global float* variables, __global const float* ff_variable, const int nelr) {
    int i = get_global_id(0);
    if (i < nelr) {
        for (int j = 0; j < NVAR; j++) {
            variables[i * NVAR + j] = ff_variable[j];
        }
    }
}

__kernel void compute_step_factor(__global const float* variables, __global const float* areas, __global float* step_factors, const int nelr) {
    int i = get_global_id(0);
    if (i < nelr) {
        float density = variables[NVAR * i + VAR_DENSITY];
        float3 momentum;
        momentum.x = variables[NVAR * i + (VAR_MOMENTUM + 0)];
        momentum.y = variables[NVAR * i + (VAR_MOMENTUM + 1)];
        momentum.z = variables[NVAR * i + (VAR_MOMENTUM + 2)];
        float density_energy = variables[NVAR * i + VAR_DENSITY_ENERGY];
        float3 velocity;
        compute_velocity(density, momentum, &velocity);
        float speed_sqd = compute_speed_sqd(velocity);
        float pressure = compute_pressure(density, density_energy, speed_sqd);
        float speed_of_sound = compute_speed_of_sound(density, pressure);
        step_factors[i] = 0.5f / (sqrt(areas[i]) * (sqrt(speed_sqd) + speed_of_sound));
    }
}

__kernel void compute_flux(__global const int* elements_surrounding_elements,
                           __global const float* normals,
                           __global const float* variables,
                           __global const float* ff_variable,
                           __global float* fluxes,
                           __global const float3* ff_flux_contribution_density_energy,
                           __global const float3* ff_flux_contribution_momentum_x,
                           __global const float3* ff_flux_contribution_momentum_y,
                           __global const float3* ff_flux_contribution_momentum_z,
                           const int nelr) {
    int i = get_global_id(0);
    if (i < nelr) {
        const float smoothing_coefficient = 0.2f;

        float density_i = variables[NVAR * i + VAR_DENSITY];
        float3 momentum_i;
        momentum_i.x = variables[NVAR * i + (VAR_MOMENTUM + 0)];
        momentum_i.y = variables[NVAR * i + (VAR_MOMENTUM + 1)];
        momentum_i.z = variables[NVAR * i + (VAR_MOMENTUM + 2)];
        float density_energy_i = variables[NVAR * i + VAR_DENSITY_ENERGY];

        float3 velocity_i;
        compute_velocity(density_i, momentum_i, &velocity_i);
        float speed_sqd_i = compute_speed_sqd(velocity_i);
        float speed_i = sqrt(speed_sqd_i);
        float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
        float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

        float3 flux_contribution_i_momentum_x = ff_flux_contribution_momentum_x[i];
        float3 flux_contribution_i_momentum_y = ff_flux_contribution_momentum_y[i];
        float3 flux_contribution_i_momentum_z = ff_flux_contribution_momentum_z[i];
        float3 flux_contribution_i_density_energy = ff_flux_contribution_density_energy[i];

        float flux_i_density = 0.0f;
        float3 flux_i_momentum = (float3)(0.0f, 0.0f, 0.0f);
        float flux_i_density_energy = 0.0f;

        for (int j = 0; j < NNB; j++) {
            int nb = elements_surrounding_elements[i * NNB + j];
            float3 normal;
            normal.x = normals[(i * NNB + j) * NDIM + 0];
            normal.y = normals[(i * NNB + j) * NDIM + 1];
            normal.z = normals[(i * NNB + j) * NDIM + 2];
            float normal_len = sqrt(normal.x * normal.x + normal.y * normal.y + normal.z * normal.z);

            if (nb >= 0) {
                float density_nb = variables[NVAR * nb + VAR_DENSITY];
                float3 momentum_nb;
                momentum_nb.x = variables[NVAR * nb + (VAR_MOMENTUM + 0)];
                momentum_nb.y = variables[NVAR * nb + (VAR_MOMENTUM + 1)];
                momentum_nb.z = variables[NVAR * nb + (VAR_MOMENTUM + 2)];
                float density_energy_nb = variables[NVAR * nb + VAR_DENSITY_ENERGY];

                float3 velocity_nb;
                compute_velocity(density_nb, momentum_nb, &velocity_nb);
                float speed_sqd_nb = compute_speed_sqd(velocity_nb);
                float pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
                float speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

                float3 flux_contribution_nb_momentum_x = ff_flux_contribution_momentum_x[nb];
                float3 flux_contribution_nb_momentum_y = ff_flux_contribution_momentum_y[nb];
                float3 flux_contribution_nb_momentum_z = ff_flux_contribution_momentum_z[nb];
                float3 flux_contribution_nb_density_energy = ff_flux_contribution_density_energy[nb];

                float factor = -normal_len * smoothing_coefficient * 0.5f * (speed_i + sqrt(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor * (density_i - density_nb);
                flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
                flux_i_momentum.x += factor * (momentum_i.x - momentum_nb.x);
                flux_i_momentum.y += factor * (momentum_i.y - momentum_nb.y);
                flux_i_momentum.z += factor * (momentum_i.z - momentum_nb.z);

                factor = 0.5f * normal.x;
                flux_i_density += factor * (momentum_nb.x + momentum_i.x);
                flux_i_density_energy += factor * (flux_contribution_nb_density_energy.x + flux_contribution_i_density_energy.x);
                flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.x + flux_contribution_i_momentum_x.x);
                flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.x + flux_contribution_i_momentum_y.x);
                flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.x + flux_contribution_i_momentum_z.x);

                factor = 0.5f * normal.y;
                flux_i_density += factor * (momentum_nb.y + momentum_i.y);
                flux_i_density_energy += factor * (flux_contribution_nb_density_energy.y + flux_contribution_i_density_energy.y);
                flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.y + flux_contribution_i_momentum_x.y);
                flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.y + flux_contribution_i_momentum_y.y);
                flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.y + flux_contribution_i_momentum_z.y);

                factor = 0.5f * normal.z;
                flux_i_density += factor * (momentum_nb.z + momentum_i.z);
                flux_i_density_energy += factor * (flux_contribution_nb_density_energy.z + flux_contribution_i_density_energy.z);
                flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.z + flux_contribution_i_momentum_x.z);
                flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.z + flux_contribution_i_momentum_y.z);
                flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.z + flux_contribution_i_momentum_z.z);
            }
            else if (nb == -1) {
                flux_i_momentum.x += normal.x * pressure_i;
                flux_i_momentum.y += normal.y * pressure_i;
                flux_i_momentum.z += normal.z * pressure_i;
            }
            else if (nb == -2) {
                float factor = 0.5f * normal.x;
                flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 0] + momentum_i.x);
                flux_i_density_energy += factor * (ff_flux_contribution_density_energy[i].x + flux_contribution_i_density_energy.x);
                flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[i].x + flux_contribution_i_momentum_x.x);
                flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[i].x + flux_contribution_i_momentum_y.x);
                flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[i].x + flux_contribution_i_momentum_z.x);

                factor = 0.5f * normal.y;
                flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 1] + momentum_i.y);
                flux_i_density_energy += factor * (ff_flux_contribution_density_energy[i].y + flux_contribution_i_density_energy.y);
                flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[i].y + flux_contribution_i_momentum_x.y);
                flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[i].y + flux_contribution_i_momentum_y.y);
                flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[i].y + flux_contribution_i_momentum_z.y);

                factor = 0.5f * normal.z;
                flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 2] + momentum_i.z);
                flux_i_density_energy += factor * (ff_flux_contribution_density_energy[i].z + flux_contribution_i_density_energy.z);
                flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[i].z + flux_contribution_i_momentum_x.z);
                flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[i].z + flux_contribution_i_momentum_y.z);
                flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[i].z + flux_contribution_i_momentum_z.z);
            }
        }

        fluxes[i * NVAR + VAR_DENSITY] = flux_i_density;
        fluxes[i * NVAR + (VAR_MOMENTUM + 0)] = flux_i_momentum.x;
        fluxes[i * NVAR + (VAR_MOMENTUM + 1)] = flux_i_momentum.y;
        fluxes[i * NVAR + (VAR_MOMENTUM + 2)] = flux_i_momentum.z;
        fluxes[i * NVAR + VAR_DENSITY_ENERGY] = flux_i_density_energy;
    }
}

__kernel void time_step(const int j, const int nelr,
                        __global const float* old_variables,
                        __global float* variables,
                        __global const float* step_factors,
                        __global const float* fluxes) {
    int i = get_global_id(0);
    if (i < nelr) {
        float factor = step_factors[i] / (float)(RK + 1 - j);

        variables[NVAR * i + VAR_DENSITY] = old_variables[NVAR * i + VAR_DENSITY] + factor * fluxes[NVAR * i + VAR_DENSITY];
        variables[NVAR * i + VAR_DENSITY_ENERGY] = old_variables[NVAR * i + VAR_DENSITY_ENERGY] + factor * fluxes[NVAR * i + VAR_DENSITY_ENERGY];
        variables[NVAR * i + (VAR_MOMENTUM + 0)] = old_variables[NVAR * i + (VAR_MOMENTUM + 0)] + factor * fluxes[NVAR * i + (VAR_MOMENTUM + 0)];
        variables[NVAR * i + (VAR_MOMENTUM + 1)] = old_variables[NVAR * i + (VAR_MOMENTUM + 1)] + factor * fluxes[NVAR * i + (VAR_MOMENTUM + 1)];
        variables[NVAR * i + (VAR_MOMENTUM + 2)] = old_variables[NVAR * i + (VAR_MOMENTUM + 2)] + factor * fluxes[NVAR * i + (VAR_MOMENTUM + 2)];
    }
}

